) ENGINE=InnoDB AUTO_INCREMENT=9830 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='抽奖决策快照表 - 记录每次抽奖的完整决策路径用于审计';
